'use strict';

var isObject = require('es-object-atoms/isObject');

var KeyForSymbol = require('./KeyForSymbol');



module.exports = function CanBeHeldWeakly(v) {
	if (isObject(v)) {
		return true; 
	}
	if (typeof v === 'symbol' && typeof KeyForSymbol(v) === 'undefined') {
		return true; 
	}
	return false; 
};
